class _ProcessMonitor:
    """Watches an editor subprocess in a background thread and invokes
    ``callback`` with ``(event_type, process_id, editor_command, timestamp)``
    for lifecycle events. Suspend/resume detection relies on ``psutil``
    being installed; if it isn't available, only ``start`` and
    ``terminate`` events are emitted.
    """

    def __init__(self, callback: MonitorCallback, poll_interval: float = 0.1) -> None:
        self.callback = callback
        self.poll_interval = poll_interval
        self._stop_event = threading.Event()
        self._thread: threading.Thread | None = None

    def _emit(self, event_type: str, process_id: int, editor_command: str) -> None:
        try:
            self.callback(event_type, process_id, editor_command, time.time())
        except Exception as e:
            warnings.warn(
                f"monitor_process callback raised an exception while handling"
                f" {event_type!r} event: {e}",
                UserWarning,
                stacklevel=2,
            )

    def start(self, process: "subprocess.Popen[t.Any]", editor_command: str) -> None:
        self._emit("start", process.pid, editor_command)
        self._thread = threading.Thread(
            target=self._run, args=(process, editor_command), daemon=True
        )
        self._thread.start()

    def _run(self, process: "subprocess.Popen[t.Any]", editor_command: str) -> None:
        try:
            import psutil

            ps_process: t.Any = psutil.Process(process.pid)
        except Exception:
            ps_process = None

        suspended = False

        while not self._stop_event.is_set():
            if process.poll() is not None:
                break

            if ps_process is not None:
                try:
                    status = ps_process.status()
                except Exception:
                    status = None

                if status == "stopped" and not suspended:
                    suspended = True
                    self._emit("suspend", process.pid, editor_command)
                elif status is not None and status != "stopped" and suspended:
                    suspended = False
                    self._emit("resume", process.pid, editor_command)

            self._stop_event.wait(self.poll_interval)

        self._emit("terminate", process.pid, editor_command)

    def stop(self) -> None:
        self._stop_event.set()
        if self._thread is not None:
            self._thread.join()


